/// Export conversation, auto-detecting format from file extension.
fn export_conversation(context: &ContextManager, path: &str) {
    let ext = path.rsplit('.').next().unwrap_or("md").to_lowercase();
    let content = match ext.as_str() {
        "html" | "htm" => export_html(context),
        "json" => export_json(context),
        "txt" => export_text(context),
        _ => export_markdown(context),
    };
    if let Err(e) = std::fs::write(path, &content) {
        eprintln!("Export failed: {}", e);
    }
}

fn role_label(role: &str) -> &str {
    match role {
        "user" => "User",
        "assistant" => "Assistant",
        "tool" => "Tool Result",
        _ => role,
    }
}

fn export_markdown(context: &ContextManager) -> String {
    let mut out = String::from("# Conversation Export\n\n");
    for m in context.get_messages() {
        out.push_str(&format!("## {}\n\n{}\n\n---\n\n", role_label(&m.role), m.content));
    }
    out
}

fn export_html(context: &ContextManager) -> String {
    let mut out = String::from("<!DOCTYPE html>\n<html><head><meta charset=\"utf-8\">\n<title>Conversation Export</title>\n<style>\nbody { font-family: sans-serif; max-width: 800px; margin: 0 auto; padding: 20px; }\n.msg { margin: 10px 0; padding: 12px; border-radius: 8px; }\n.user { background: #dbeafe; }\n.assistant { background: #f3f4f6; }\n.tool { background: #fef3c7; font-family: monospace; font-size: 0.9em; }\npre { background: #1e1e1e; color: #d4d4d4; padding: 10px; border-radius: 4px; overflow-x: auto; }\n</style></head><body>\n<h1>Conversation Export</h1>\n");
    for m in context.get_messages() {
        let css_class = match m.role.as_str() {
            "user" => "user",
            "assistant" => "assistant",
            _ => "tool",
        };
        let escaped = m.content
            .replace('&', "&amp;")
            .replace('<', "&lt;")
            .replace('>', "&gt;")
            .replace('"', "&quot;");
        out.push_str(&format!("<div class=\"msg {}\"><strong>{}</strong><br>{}\n</div>\n", css_class, role_label(&m.role), escaped));
    }
    out.push_str("</body></html>\n");
    out
}

fn export_json(context: &ContextManager) -> String {
    let messages: Vec<serde_json::Value> = context.get_messages().iter().map(|m| {
        serde_json::json!({
            "role": m.role,
            "content": m.content
        })
    }).collect();
    let doc = serde_json::json!({
        "exported": chrono_now_iso8601(),
        "message_count": context.len(),
        "messages": messages
    });
    serde_json::to_string_pretty(&doc).unwrap_or_default()
}

fn export_text(context: &ContextManager) -> String {
    let mut out = String::from("Conversation Export\n");
    out.push_str(&format!("Messages: {}\n", context.len()));
    out.push_str("========================================\n\n");
    for m in context.get_messages() {
        out.push_str(&format!("{}: {}\n", role_label(&m.role), m.content));
        out.push_str("----------------------------------------\n\n");
    }
    out
}

fn chrono_now_iso8601() -> String {
    let dur = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default();
    format!("{}", dur.as_secs())
}


/// Reload config from disk, returning list of changed fields.
fn reload_config(config: &mut AgentConfig, state: &mut RuntimeState) -> Result<Vec<String>, String> {
    let path = find_config_file(None, false).ok_or("No config file found")?;
    let cf = load_config_file(&path).ok_or(format!("Failed to parse {}", path))?;
    let fresh = resolve_agent(Some(&config.name), Some(&cf));
    let mut changes = Vec::new();

    if config.backend != fresh.backend {
        changes.push(format!("backend: {} -> {}", config.backend, fresh.backend));
        config.backend = fresh.backend.clone();
    }
    if config.model != fresh.model {
        changes.push(format!("model: {:?} -> {:?}", config.model, fresh.model));
        config.model = fresh.model.clone();
    }
    if config.system_prompt != fresh.system_prompt {
        changes.push("system_prompt updated".to_string());
        config.system_prompt = fresh.system_prompt.clone();
    }
    if config.approval_mode != fresh.approval_mode {
        changes.push(format!("approval_mode: {} -> {}", config.approval_mode, fresh.approval_mode));
        config.approval_mode = fresh.approval_mode.clone();
    }
    if config.security_profile != fresh.security_profile {
        changes.push(format!("security_profile: {} -> {}", config.security_profile, fresh.security_profile));
        config.security_profile = fresh.security_profile.clone();
    }
    if config.stream != fresh.stream {
        changes.push(format!("stream: {} -> {}", config.stream, fresh.stream));
        config.stream = fresh.stream;
        state.stream = fresh.stream;
    }
    if config.max_iterations != fresh.max_iterations {
        changes.push(format!("max_iterations: {} -> {}", config.max_iterations, fresh.max_iterations));
        config.max_iterations = fresh.max_iterations;
        state.max_iterations = fresh.max_iterations;
    }
    Ok(changes)
}


/// Configuration for retry with exponential backoff.
pub struct RetryConfig {
    pub max_attempts: u32,
    pub base_delay_secs: f64,
    pub max_delay_secs: f64,
    pub exponential_base: f64,
    pub jitter: bool,
}

impl Default for RetryConfig {
    fn default() -> Self {
        Self {
            max_attempts: 3,
            base_delay_secs: 1.0,
            max_delay_secs: 60.0,
            exponential_base: 2.0,
            jitter: true,
        }
    }
}

/// Check if an HTTP status code is retryable.
pub fn is_retryable_status(status: u16) -> bool {
    matches!(status, 408 | 429 | 500 | 502 | 503 | 504)
}

/// Simple pseudo-random jitter based on system time.
fn jitter_factor() -> f64 {
    let nanos = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .subsec_nanos();
    0.5 + (nanos as f64 % 1000.0) / 2000.0
}

/// Retry a fallible operation with exponential backoff.
pub fn retry_with_backoff<F, T>(config: &RetryConfig, mut f: F) -> Result<T, String>
where
    F: FnMut() -> Result<T, String>,
{
    let mut last_err = String::new();
    for attempt in 1..=config.max_attempts {
        match f() {
            Ok(val) => return Ok(val),
            Err(e) => {
                last_err = e;
                if attempt == config.max_attempts {
                    break;
                }
                let mut delay = config.base_delay_secs
                    * config.exponential_base.powi((attempt - 1) as i32);
                if delay > config.max_delay_secs {
                    delay = config.max_delay_secs;
                }
                if config.jitter {
                    delay *= jitter_factor();
                }
                eprintln!("Retry {}/{} in {:.1}s: {}", attempt, config.max_attempts, delay, last_err);
                std::thread::sleep(std::time::Duration::from_secs_f64(delay));
            }
        }
    }
    Err(format!("Failed after {} attempts: {}", config.max_attempts, last_err))
}

/// Async retry wrapper with exponential backoff for async backends.
pub async fn retry_async<F, Fut, T>(config: &RetryConfig, mut f: F) -> Result<T, String>
where
    F: FnMut() -> Fut,
    Fut: std::future::Future<Output = Result<T, String>>,
{
    let mut last_err = String::new();
    for attempt in 1..=config.max_attempts {
        match f().await {
            Ok(val) => return Ok(val),
            Err(e) => {
                last_err = e;
                if attempt == config.max_attempts {
                    break;
                }
                let mut delay = config.base_delay_secs
                    * config.exponential_base.powi((attempt - 1) as i32);
                if delay > config.max_delay_secs {
                    delay = config.max_delay_secs;
                }
                if config.jitter {
                    delay *= jitter_factor();
                }
                eprintln!("Retry {}/{} in {:.1}s: {}", attempt, config.max_attempts, delay, last_err);
                tokio::time::sleep(std::time::Duration::from_secs_f64(delay)).await;
            }
        }
    }
    Err(format!("Failed after {} attempts: {}", config.max_attempts, last_err))
}


use std::collections::HashMap;

/// A prompt template with variable placeholders.
#[derive(Debug, Clone)]
pub struct Template {
    pub name: String,
    pub template: String,
    pub description: String,
    pub variables: Vec<String>,
}

/// Manages built-in and user-defined prompt templates.
pub struct TemplateManager {
    templates: HashMap<String, Template>,
    config_path: std::path::PathBuf,
}

impl TemplateManager {
    pub fn new() -> Self {
        let config_path = dirs_config_path("templates.json");
        let mut mgr = Self { templates: HashMap::new(), config_path };
        // 16 built-in templates
        mgr.add_builtin("explain", "Explain the following code or concept:\n\n{input}", "Explain code or concept");
        mgr.add_builtin("review", "Review this code for {focus}:\n\n{code}", "Code review with focus area");
        mgr.add_builtin("refactor", "Refactor this code to improve {aspect}:\n\n{code}", "Refactor code");
        mgr.add_builtin("test", "Write tests for:\n\n{code}", "Generate tests");
        mgr.add_builtin("fix", "Fix the following bug or error:\n\n{input}", "Fix a bug");
        mgr.add_builtin("summarize", "Summarize the following:\n\n{input}", "Summarize text");
        mgr.add_builtin("convert", "Convert this {from_lang} code to {to_lang}:\n\n{code}", "Convert between languages");
        mgr.add_builtin("translate", "Translate to {language}:\n\n{input}", "Translate text");
        mgr.add_builtin("simplify", "Simplify this code while preserving behavior:\n\n{code}", "Simplify code");
        mgr.add_builtin("debug", "Debug this issue:\n\n{input}", "Debug a problem");
        mgr.add_builtin("optimize", "Optimize this code for {goal}:\n\n{code}", "Optimize code");
        mgr.add_builtin("regex", "Write a regex pattern that matches: {description}", "Generate regex");
        mgr.add_builtin("sql", "Write a SQL query to: {description}", "Generate SQL");
        mgr.add_builtin("bash", "Write a bash command to: {description}", "Generate bash");
        mgr.add_builtin("git", "Write git commands to: {description}", "Generate git commands");
        mgr.add_builtin("doc", "Write documentation for:\n\n{code}", "Generate docs");
        // Load user templates from config
        mgr.load_user_templates();
        mgr
    }

    fn add_builtin(&mut self, name: &str, template: &str, description: &str) {
        let variables = Self::extract_variables(template);
        self.templates.insert(name.to_string(), Template {
            name: name.to_string(),
            template: template.to_string(),
            description: description.to_string(),
            variables,
        });
    }

    fn extract_variables(template: &str) -> Vec<String> {
        let mut vars = Vec::new();
        let mut i = 0;
        let bytes = template.as_bytes();
        while i < bytes.len() {
            if bytes[i] == b'{' {
                if let Some(end) = template[i+1..].find('}') {
                    let var = &template[i+1..i+1+end];
                    if var.chars().all(|c| c.is_alphanumeric() || c == '_') {
                        if !vars.contains(&var.to_string()) {
                            vars.push(var.to_string());
                        }
                    }
                    i += end + 2;
                    continue;
                }
            }
            i += 1;
        }
        vars
    }

    /// Render a template with provided variables.
    pub fn render(&self, name: &str, vars: &HashMap<String, String>) -> Option<String> {
        let tmpl = self.templates.get(name)?;
        let mut result = tmpl.template.clone();
        for (k, v) in vars {
            result = result.replace(&format!("{{{}}}", k), v);
        }
        Some(result)
    }

    /// List all available templates.
    pub fn list(&self) -> Vec<&Template> {
        let mut templates: Vec<_> = self.templates.values().collect();
        templates.sort_by_key(|t| &t.name);
        templates
    }

    /// Add a user-defined template.
    pub fn add(&mut self, name: &str, template: &str, description: &str) {
        let variables = Self::extract_variables(template);
        self.templates.insert(name.to_string(), Template {
            name: name.to_string(),
            template: template.to_string(),
            description: description.to_string(),
            variables,
        });
    }

    /// Get a template by name.
    pub fn get(&self, name: &str) -> Option<&Template> {
        self.templates.get(name)
    }

    /// Load user-defined templates from JSON config file.
    fn load_user_templates(&mut self) {
        if let Ok(data) = std::fs::read_to_string(&self.config_path) {
            if let Ok(json) = serde_json::from_str::<serde_json::Value>(&data) {
                if let Some(obj) = json.as_object() {
                    for (name, val) in obj {
                        if let Some(tmpl_str) = val.get("template").and_then(|v| v.as_str()) {
                            let desc = val.get("description").and_then(|v| v.as_str()).unwrap_or("");
                            self.add(name, tmpl_str, desc);
                        }
                    }
                }
            }
        }
    }

    /// Save user-defined templates (non-builtins) to JSON config file.
    pub fn save_user_templates(&self) {
        let builtins = ["explain","review","refactor","test","fix","summarize",
                        "convert","translate","simplify","debug","optimize",
                        "regex","sql","bash","git","doc"];
        let mut obj = serde_json::Map::new();
        for (name, tmpl) in &self.templates {
            if !builtins.contains(&name.as_str()) {
                obj.insert(name.clone(), serde_json::json!({
                    "template": tmpl.template,
                    "description": tmpl.description
                }));
            }
        }
        if !obj.is_empty() {
            if let Some(parent) = self.config_path.parent() {
                let _ = std::fs::create_dir_all(parent);
            }
            let _ = std::fs::write(&self.config_path,
                serde_json::to_string_pretty(&serde_json::Value::Object(obj)).unwrap_or_default());
        }
    }
}

/// Get config path under ~/.agent-loop/
fn dirs_config_path(filename: &str) -> std::path::PathBuf {
    let home = std::env::var("HOME").unwrap_or_else(|_| ".".to_string());
    std::path::PathBuf::from(home).join(".agent-loop").join(filename)
}


/// Load an agent.md file as a string.
pub fn load_agent_md(path: &str) -> Option<String> {
    std::fs::read_to_string(path).ok()
}

/// Load multiple skill files, returning their contents.
pub fn load_skills(paths: &[String]) -> Vec<String> {
    paths.iter()
        .filter_map(|p| std::fs::read_to_string(p).ok())
        .collect()
}

/// Build the final system prompt from agent.md, skills, and base prompt.
pub fn build_system_prompt(agent_md: Option<&str>, skills: &[String], base: Option<&str>) -> String {
    let mut parts = Vec::new();
    if let Some(md) = agent_md {
        parts.push(md.to_string());
    }
    if !skills.is_empty() {
        parts.push("## Skills\n".to_string());
        for skill in skills {
            parts.push(format!("---\n{}\n", skill));
        }
    }
    if let Some(b) = base {
        parts.push(b.to_string());
    }
    parts.join("\n\n")
}


/// Handles multi-line input detection, paste detection, and continuation.
pub struct MultilineHandler {
    pub explicit_mode: bool,
}

/// Result of paste detection: either a single line or a multi-line paste.
pub enum PasteResult {
    SingleLine(String),
    Pasted { content: String, line_count: usize, char_count: usize },
}

impl MultilineHandler {
    pub fn new() -> Self {
        Self { explicit_mode: false }
    }

    /// Detect if additional lines are available on stdin (indicating a paste).
    /// Uses non-blocking read with a short delay to check for buffered input.
    pub fn detect_paste(first_line: &str) -> PasteResult {
        use std::io::{self, BufRead};

        // Only detect pastes from a real terminal
        if !atty_is_tty() {
            return PasteResult::SingleLine(first_line.to_string());
        }

        let mut lines = vec![first_line.to_string()];

        // Short delay to let pasted data arrive in the buffer
        std::thread::sleep(std::time::Duration::from_millis(50));

        // Try to read any buffered lines from stdin without blocking
        let stdin = io::stdin();
        let mut handle = stdin.lock();

        loop {
            let available = {
                match handle.fill_buf() {
                    Ok(buf) => buf.len(),
                    Err(_) => 0,
                }
            };
            if available == 0 {
                break;
            }
            let mut line = String::new();
            match handle.read_line(&mut line) {
                Ok(0) => break,
                Ok(_) => {
                    lines.push(line.trim_end_matches('\n').trim_end_matches('\r').to_string());
                }
                Err(_) => break,
            }
        }

        if lines.len() > 1 {
            let content = lines.join("\n");
            let line_count = lines.len();
            let char_count = content.len();
            PasteResult::Pasted { content, line_count, char_count }
        } else {
            PasteResult::SingleLine(first_line.to_string())
        }
    }

    /// Check if a line needs continuation (triggers multi-line mode).
    pub fn needs_continuation(line: &str) -> bool {
        let trimmed = line.trim();
        // Triple backticks
        if trimmed.starts_with("```") && !trimmed[3..].contains("```") {
            return true;
        }
        // Heredoc
        if trimmed.starts_with("<<<") {
            return true;
        }
        // Backslash continuation
        if trimmed.ends_with('\\') {
            return true;
        }
        // Unbalanced brackets
        let mut depth = 0i32;
        for ch in trimmed.chars() {
            match ch {
                '{' | '[' | '(' => depth += 1,
                '}' | ']' | ')' => depth -= 1,
                _ => {}
            }
        }
        depth > 0
    }

    /// Read lines until the trigger condition is satisfied.
    pub fn read_until_complete(first_line: &str, rl: &mut rustyline::DefaultEditor) -> String {
        let mut lines = vec![first_line.to_string()];
        let trimmed = first_line.trim();

        if trimmed.starts_with("```") {
            // Read until closing backticks
            loop {
                match rl.readline("... ") {
                    Ok(line) => {
                        let done = line.trim() == "```";
                        lines.push(line);
                        if done { break; }
                    }
                    Err(_) => break,
                }
            }
        } else if trimmed.starts_with("<<<") {
            // Heredoc: read until marker
            let marker = trimmed[3..].trim().to_string();
            let marker = if marker.is_empty() { "EOF".to_string() } else { marker };
            loop {
                match rl.readline("... ") {
                    Ok(line) => {
                        if line.trim() == marker { break; }
                        lines.push(line);
                    }
                    Err(_) => break,
                }
            }
        } else if trimmed.ends_with('\\') {
            // Backslash continuation
            if let Some(last) = lines.last_mut() {
                *last = last.trim_end_matches('\\').to_string();
            }
            loop {
                match rl.readline("... ") {
                    Ok(line) => {
                        if line.trim().ends_with('\\') {
                            lines.push(line.trim_end_matches('\\').to_string());
                        } else {
                            lines.push(line);
                            break;
                        }
                    }
                    Err(_) => break,
                }
            }
        } else {
            // Bracket balancing
            loop {
                let combined = lines.join("\n");
                let mut depth = 0i32;
                for ch in combined.chars() {
                    match ch {
                        '{' | '[' | '(' => depth += 1,
                        '}' | ']' | ')' => depth -= 1,
                        _ => {}
                    }
                }
                if depth <= 0 { break; }
                match rl.readline("... ") {
                    Ok(line) => lines.push(line),
                    Err(_) => break,
                }
            }
        }
        lines.join("\n")
    }

    /// Read lines in explicit multi-line mode until empty line or EOF.
    pub fn read_explicit(&self, rl: &mut rustyline::DefaultEditor) -> String {
        let mut lines = Vec::new();
        loop {
            match rl.readline("... ") {
                Ok(line) => {
                    if line.trim().is_empty() && !lines.is_empty() { break; }
                    lines.push(line);
                }
                Err(_) => break,
            }
        }
        lines.join("\n")
    }
}

/// Check if stdin is a TTY (terminal).
fn atty_is_tty() -> bool {
    unsafe { libc_isatty(0) != 0 }
}

extern "C" {
    #[link_name = "isatty"]
    fn libc_isatty(fd: i32) -> i32;
}


use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;

/// A simple terminal spinner that shows activity during API calls.
pub struct Spinner {
    running: Arc<AtomicBool>,
    handle: Option<std::thread::JoinHandle<()>>,
}

impl Spinner {
    /// Start a spinner with a message.
    pub fn start(msg: &str) -> Self {
        let running = Arc::new(AtomicBool::new(true));
        let r = running.clone();
        let msg = msg.to_string();
        let handle = std::thread::spawn(move || {
            let frames = ["|", "/", "-", "\\"];
            let mut i = 0;
            let start = std::time::Instant::now();
            while r.load(Ordering::Relaxed) {
                let elapsed = start.elapsed().as_secs();
                eprint!("\r  {} {} ({}s) ", frames[i % frames.len()], msg, elapsed);
                i += 1;
                std::thread::sleep(std::time::Duration::from_millis(120));
            }
            eprint!("\r                                                    \r");
        });
        Self { running, handle: Some(handle) }
    }

    /// Stop the spinner.
    pub fn stop(mut self) {
        self.running.store(false, Ordering::Relaxed);
        if let Some(h) = self.handle.take() {
            let _ = h.join();
        }
    }
}

impl Drop for Spinner {
    fn drop(&mut self) {
        self.running.store(false, Ordering::Relaxed);
    }
}

/// Handle a slash command. Returns true if the command was handled.
/// Mutable runtime state that can be changed via slash commands.
struct RuntimeState {
    max_iterations: i64,
    stream: bool,
    show_tokens: bool,
    multiline: bool,
    paste_mode: String,
}

fn handle_command(
    input: &str,
    context: &mut ContextManager,
    cost_tracker: &CostTracker,
    session_manager: &SessionManager,
    backend_name: &str,
    state: &mut RuntimeState,
    config: &mut AgentConfig,
) -> bool {
    let parts: Vec<&str> = input.splitn(2, ' ').collect();
    let cmd = parts[0].trim_start_matches('/');
    let _arg = if parts.len() > 1 { parts[1].trim() } else { "" };
    match cmd {
        "exit" | "quit" => {
            // Auto-save on exit
            if context.len() > 0 {
                let id = session_manager.save(context.get_messages(), backend_name, None);
                println!("Session saved: {}", id);
            }
            println!("Goodbye!");
            std::process::exit(0);
        }
        "clear" => {
            context.clear();
            println!("Context cleared.");
        }
        "help" => {
            println!("Available commands:");
            println!();
            println!("Commands (with or without / prefix):");
            println!("  /exit, /quit       - Exit the agent loop");
            println!("  /clear             - Clear conversation context");
            println!("  /status            - Show context status");
            println!("  /help              - Show this help message");
            println!();
            println!("Loop Control:");
            println!("  /iterations [N]    - Show or set max iterations (0 = unlimited)");
            println!("  /backend [name]    - Show or switch backend/agent");
            println!("  /model [name]      - Show or switch model at runtime");
            println!("  /format [type]     - Set context format (plain/markdown/json/xml)");
            println!("  /stream            - Toggle streaming mode for API backends");
            println!();
            println!("Sessions:");
            println!("  /save [name]       - Save current conversation");
            println!("  /load <id>         - Load a saved conversation");
            println!("  /sessions          - List saved sessions");
            println!("  /search <query>    - Search across saved sessions");
            println!();
            println!("Export & Costs:");
            println!("  /export <path>     - Export conversation (.md, .html, .json, .txt)");
            println!("  /cost              - Show API cost tracking summary");
            println!("  /tokens            - Show context token estimate and limit");
            println!();
            println!("History:");
            println!("  /history [n]       - Show last n messages (default 10)");
            println!("  /delete <idx>      - Delete message at index");
            println!("  /delete <s>-<e>    - Delete messages from s to e");
            println!("  /delete last [n]   - Delete last n messages");
            println!("  /edit <idx>        - Edit message at index");
            println!("  /replay <idx>      - Re-send message at index");
            println!("  /undo              - Undo last history change");
            println!();
            println!("Shortcuts:");
            println!("  /aliases           - List command aliases (e.g., /q -> /quit)");
            println!("  /templates         - List prompt templates");
            println!();
            println!("Config:");
            println!("  /init [path]       - Create example config file (default: uwsal.json)");
            println!("  /reload            - Reload config from disk (hot-reload model, backend, system_prompt)");
            println!("  /clear-cache       - Flush the tool result cache");
            println!();
            println!("Multi-line Input:");
            println!("  Start with ``` for code blocks");
            println!("  Start with <<< for heredoc mode");
            println!("  End lines with \\\\ for continuation");
            println!();
            println!("Just type your message to chat with the agent.");
        }
        "status" => {
            println!("Context: {} messages", context.len());
            println!("{}", cost_tracker.format_summary());
        }
        "iterations" => {
            if _arg.is_empty() {
                println!("Max iterations: {} (0 = unlimited)", state.max_iterations);
            } else if let Ok(n) = _arg.parse::<i64>() {
                state.max_iterations = n;
                println!("Max iterations set to: {}", n);
            } else {
                println!("Usage: /iterations <N>");
            }
        }
        "backend" => {
            if _arg.is_empty() {
                println!("Current backend: {}", backend_name);
            } else {
                println!("Backend switch requires restart: uwsal -b {}", _arg);
            }
        }
        "save" => {
            let name = if _arg.is_empty() { None } else { Some(_arg) };
            let id = session_manager.save(context.get_messages(), backend_name, name);
            println!("Session saved: {}", id);
        }
        "load" => {
            if _arg.is_empty() {
                println!("Usage: /load <session-id>");
            } else if let Some(session) = session_manager.load(_arg) {
                context.clear();
                for msg in &session.messages {
                    context.add_message(&msg.role, &msg.content);
                }
                println!("Loaded session: {} ({} messages)", session.metadata.name, session.metadata.message_count);
            } else {
                println!("Session not found: {}", _arg);
            }
        }
        "sessions" => {
            let sessions = session_manager.list();
            if sessions.is_empty() {
                println!("No saved sessions.");
            } else {
                for s in &sessions {
                    println!("{} | {} | {} | {} msgs", s.id, s.name, s.backend, s.message_count);
                }
            }
        }
        "format" => {
            println!("Output format: plain (markdown rendering not yet implemented)");
        }
        "export" => {
            let path = if _arg.is_empty() {
                format!("conversation_{}.md", session_manager.chrono_simple_id())
            } else { _arg.to_string() };
            export_conversation(context, &path);
            println!("Exported to: {}", path);
        }
        "cost" | "costs" => {
            println!("{}", cost_tracker.format_summary());
        }
        "search" => {
            if _arg.is_empty() {
                println!("Usage: /search <query>");
            } else {
                let query_lower = _arg.to_lowercase();
                let sessions = session_manager.list();
                let mut found = false;
                for s in &sessions {
                    if s.name.to_lowercase().contains(&query_lower) || s.id.contains(&query_lower) {
                        println!("{} | {} | {}", s.id, s.name, s.backend);
                        found = true;
                    }
                }
                if !found { println!("No sessions matching: {}", _arg); }
            }
        }
        "stream" | "streaming" => {
            state.stream = !state.stream;
            println!("Streaming: {}", if state.stream { "on" } else { "off" });
        }
        "model" => {
            if _arg.is_empty() {
                println!("Current backend: {}", backend_name);
            } else {
                println!("Model switch requires restart: uwsal -m {}", _arg);
            }
        }
        "tokens" => {
            println!("Messages: {}", context.len());
            println!("Chars: {}", context.char_count());
            println!("Est. tokens: ~{}", context.estimate_tokens());
        }
        "multiline" => {
            state.multiline = !state.multiline;
            println!("Multiline mode: {}", if state.multiline { "on" } else { "off" });
        }
        "aliases" => {
            println!("Command aliases:");
            println!("  /q, /quit  -> /exit");
            println!("  /h, /?    -> /help");
            println!("  /costs    -> /cost");
            println!("  /del      -> /delete");
        }
        "templates" | "template" => {
            let mut tmgr = TemplateManager::new();
            if _arg.is_empty() || _arg == "list" {
                for t in tmgr.list() {
                    println!("  @{:<12} {} [{}]", t.name, t.description, t.variables.join(", "));
                }
            } else if _arg.starts_with("use ") {
                let rest = &_arg[4..];
                let parts: Vec<&str> = rest.splitn(2, ' ').collect();
                let name = parts[0];
                let mut vars = std::collections::HashMap::new();
                if let Some(args_str) = parts.get(1) {
                    for pair in args_str.split(' ') {
                        if let Some((k, v)) = pair.split_once('=') {
                            vars.insert(k.to_string(), v.to_string());
                        }
                    }
                }
                if let Some(rendered) = tmgr.render(name, &vars) {
                    println!("Template rendered:\n{}", rendered);
                } else {
                    println!("Unknown template: {}", name);
                }
            } else if _arg.starts_with("add ") {
                let rest = &_arg[4..];
                let parts: Vec<&str> = rest.splitn(2, ' ').collect();
                if parts.len() == 2 {
                    tmgr.add(parts[0], parts[1], "User template");
                    tmgr.save_user_templates();
                    println!("Template added: {}", parts[0]);
                } else {
                    println!("Usage: /template add <name> <template string with {{vars}}>");
                }
            } else {
                println!("Usage: /template [list | use <name> key=val ... | add <name> <template>]");
            }
        }
        "history" => {
            let limit = _arg.parse::<usize>().unwrap_or(20);
            print!("{}", context.format_history(limit));
        }
        "undo" => {
            if context.undo() {
                println!("Undone. Messages: {}", context.len());
            } else {
                println!("Nothing to undo.");
            }
        }
        "delete" | "del" => {
            if _arg.contains('-') {
                let parts: Vec<&str> = _arg.split('-').collect();
                if let (Some(s), Some(e)) = (parts.first().and_then(|s| s.parse::<usize>().ok()), parts.get(1).and_then(|s| s.parse::<usize>().ok())) {
                    let n = context.delete_range(s, e + 1);
                    println!("Dropped {} messages", n);
                } else {
                    println!("Usage: /drop <N> or /drop <N>-<M>");
                }
            } else if let Ok(idx) = _arg.parse::<usize>() {
                if context.delete_message(idx) {
                    println!("Dropped message {}", idx);
                } else {
                    println!("Invalid index: {}", idx);
                }
            } else {
                println!("Usage: /drop <N> or /drop <N>-<M>");
            }
        }
        "edit" => {
            let parts: Vec<&str> = _arg.splitn(2, ' ').collect();
            if let Some(idx) = parts.first().and_then(|s| s.parse::<usize>().ok()) {
                if let Some(text) = parts.get(1) {
                    if context.edit_message(idx, text) {
                        println!("Edited message {}", idx);
                    } else {
                        println!("Invalid index: {}", idx);
                    }
                } else {
                    if let Some(content) = context.get_full_content(idx) {
                        println!("{}", content);
                    } else {
                        println!("Invalid index: {}", idx);
                    }
                }
            } else {
                println!("Usage: /edit <index> [new text]");
            }
        }
        "replay" => {
            if let Ok(idx) = _arg.parse::<usize>() {
                if idx < context.len() {
                    context.truncate_after(idx);
                    println!("Replaying from message {}", idx);
                } else {
                    println!("Invalid index: {}", idx);
                }
            } else {
                println!("Usage: /replay <index>");
            }
        }
        "init" => {
            let path = if _arg.is_empty() { "uwsal.json" } else { _arg };
            match init_config(path) {
                Ok(()) => {}
                Err(e) => println!("Error: {}", e),
            }
        }
        "reload" => {
            match reload_config(config, state) {
                Ok(changes) => {
                    if changes.is_empty() {
                        println!("  Config unchanged.");
                    } else {
                        for change in &changes {
                            println!("  Reloaded: {}", change);
                        }
                    }
                }
                Err(e) => println!("  Reload error: {}", e),
            }
        }
        _ => {
            println!("Unknown command: /{}", cmd);
            return false;
        }
    }
    true
}

#[tokio::main]
async fn main() {
    let matches = clap::Command::new("uwsal")
        .about("UnifyWeaver Agent Loop")
        .version(env!("CARGO_PKG_VERSION"))
        .arg(clap::Arg::new("agent")
            .long("agent")
            .short('a')
            .help("Agent variant from config file (e.g., yolo, claude-opus, ollama)"))
        .arg(clap::Arg::new("config")
            .long("config")
            .short('C')
            .help("Path to config file (agents.yaml or agents.json)"))
        .arg(clap::Arg::new("list_agents")
            .long("list-agents")
            .help("List available agent variants from config")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("init_config")
            .long("init-config")
            .help("Create example config file at PATH"))
        .arg(clap::Arg::new("backend")
            .long("backend")
            .short('b')
            .help("Backend to use (overrides --agent config)")
            .value_parser(["coro", "claude", "claude-code", "gemini", "openai", "openrouter", "ollama-api", "ollama-cli"]))
        .arg(clap::Arg::new("command")
            .long("command")
            .short('c')
            .help("Command for CLI backends"))
        .arg(clap::Arg::new("model")
            .long("model")
            .short('m')
            .help("Model to use"))
        .arg(clap::Arg::new("host")
            .long("host")
            .help("Host for network backends (ollama-api)"))
        .arg(clap::Arg::new("port")
            .long("port")
            .help("Port for network backends (ollama-api)")
            .value_parser(clap::value_parser!(i64)))
        .arg(clap::Arg::new("api_key")
            .long("api-key")
            .help("API key (overrides env vars and config files)"))
        .arg(clap::Arg::new("no_tokens")
            .long("no-tokens")
            .help("Hide token usage information")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("context_mode")
            .long("context-mode")
            .help("Context behavior mode")
            .value_parser(["continue", "fresh", "sliding"]))
        .arg(clap::Arg::new("max_chars")
            .long("max-chars")
            .help("Max characters in context (0 = unlimited)")
            .default_value("0")
            .value_parser(clap::value_parser!(i64)))
        .arg(clap::Arg::new("max_words")
            .long("max-words")
            .help("Max words in context (0 = unlimited)")
            .default_value("0")
            .value_parser(clap::value_parser!(i64)))
        .arg(clap::Arg::new("max_tokens")
            .long("max-tokens")
            .help("Max tokens in context (default: 100000, uses estimation)")
            .value_parser(clap::value_parser!(i64)))
        .arg(clap::Arg::new("auto_tools")
            .long("auto-tools")
            .help("Auto-execute tools without confirmation")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("no_tools")
            .long("no-tools")
            .help("Disable tool execution")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("sandbox")
            .long("sandbox")
            .help("Run in sandbox mode (gemini: requires docker/podman)")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("approval_mode")
            .long("approval-mode")
            .help("Tool approval mode (default: yolo). default=prompt, auto_edit=auto-approve edits, yolo=auto-approve all, plan=read-only")
            .default_value("yolo")
            .value_parser(["default", "auto_edit", "yolo", "plan"]))
        .arg(clap::Arg::new("allowed_tools")
            .long("allowed-tools")
            .help("Specific tools allowed without confirmation")
            .num_args(0..))
        .arg(clap::Arg::new("system_prompt")
            .long("system-prompt")
            .help("System prompt to use"))
        .arg(clap::Arg::new("no_fallback")
            .long("no-fallback")
            .help("Skip coro.json fallback for commands and config (uwsal.json still checked)")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("max_iterations")
            .long("max-iterations")
            .short('i')
            .help("Max tool iterations before pausing (0 = unlimited)")
            .value_parser(clap::value_parser!(i64)))
        .arg(clap::Arg::new("security_profile")
            .long("security-profile")
            .help("Security profile (default: cautious). open=no checks, cautious=path+command validation, guarded=proxy+audit+extra blocks, paranoid=allowlist-only")
            .value_parser(["open", "cautious", "guarded", "paranoid"]))
        .arg(clap::Arg::new("no_security")
            .long("no-security")
            .help("Disable all security checks (alias for --security-profile open)")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("path_proxy")
            .long("path-proxy")
            .help("Enable PATH-based command proxying (wrapper scripts in ~/.agent-loop/bin/)")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("proot")
            .long("proot")
            .help("Enable proot filesystem sandboxing (requires: pkg install proot)")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("proot_allow_dir")
            .long("proot-allow-dir")
            .help("Additional directory to bind into proot sandbox (repeatable)")
            .action(clap::ArgAction::Append))
        .arg(clap::Arg::new("session")
            .long("session")
            .short('s')
            .help("Load a saved session by ID"))
        .arg(clap::Arg::new("list_sessions")
            .long("list-sessions")
            .help("List saved sessions")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("sessions_dir")
            .long("sessions-dir")
            .help("Directory for session files (default: ~/.agent-loop/sessions)"))
        .arg(clap::Arg::new("context_format")
            .long("context-format")
            .help("Format for context when sent to backend")
            .value_parser(["plain", "markdown", "json", "xml"]))
        .arg(clap::Arg::new("stream_arg")
            .long("stream")
            .help("Enable streaming output for API backends")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("no_cost_tracking")
            .long("no-cost-tracking")
            .help("Disable cost tracking")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("search_arg")
            .long("search")
            .help("Search across saved sessions and exit"))
        .arg(clap::Arg::new("fancy")
            .long("fancy")
            .help("Enable ncurses display mode with spinner (uses tput)")
            .action(clap::ArgAction::SetTrue))
        .arg(clap::Arg::new("prompt_interactive")
            .long("prompt-interactive")
            .short('I')
            .help("Start interactive mode with an initial prompt"))
        .arg(clap::Arg::new("prompt")
            .help("Single prompt to run (non-interactive mode)")
            .num_args(0..=1))
        .get_matches();

    // Load config file
    let no_fallback = matches.get_flag("no_fallback");
    let cli_config = matches.get_one::<String>("config").map(|s| s.as_str());
    let config_path = find_config_file(cli_config, no_fallback);
    let config_file = config_path.as_deref().and_then(|p| load_config_file(p));

    // Handle --init-config
    if let Some(path) = matches.get_one::<String>("init_config") {
        if let Err(e) = init_config(path) {
            eprintln!("Error creating config: {}", e);
        }
        return;
    }

    // Handle --list-agents
    if matches.get_flag("list_agents") {
        list_agents(config_file.as_ref());
        return;
    }

    // Resolve agent variant
    let agent_name = matches.get_one::<String>("agent").map(|s| s.as_str());
    let mut config = resolve_agent(agent_name, config_file.as_ref());

    // Apply CLI overrides on top of agent config
    if let Some(v) = matches.get_one::<String>("backend") { config.backend = v.clone(); }
    if let Some(v) = matches.get_one::<String>("model") { config.model = Some(v.clone()); }
    if let Some(v) = matches.get_one::<String>("api_key") { config.api_key = Some(v.clone()); }
    if let Some(v) = matches.get_one::<String>("system_prompt") { config.system_prompt = Some(v.clone()); }
    if matches.get_flag("auto_tools") { config.auto_tools = true; }
    if matches.get_flag("no_tokens") { config.show_tokens = false; }
    if matches.get_flag("stream_arg") { config.stream = true; }
    if matches.get_flag("no_security") { config.security_profile = "open".to_string(); }
    if let Some(v) = matches.get_one::<String>("security_profile") { config.security_profile = v.clone(); }
    if let Some(v) = matches.get_one::<String>("approval_mode") { config.approval_mode = v.clone(); }
    if let Some(&v) = matches.get_one::<i64>("max_iterations") { config.max_iterations = v; }
    if let Some(&v) = matches.get_one::<i64>("max_tokens") { config.max_context_tokens = v; }
    if let Some(&v) = matches.get_one::<i64>("max_chars") { config.max_chars = v; }
    if let Some(&v) = matches.get_one::<i64>("max_words") { config.max_words = v; }

    // Resolve API key
    resolve_api_key(&mut config, config_file.as_ref());

    let sessions_dir = matches.get_one::<String>("sessions_dir").map(|s| s.as_str());
    let session_manager = SessionManager::new(sessions_dir);

    // Handle --list-sessions
    if matches.get_flag("list_sessions") {
        let sessions = session_manager.list();
        if sessions.is_empty() {
            println!("No saved sessions.");
        } else {
            for s in &sessions {
                println!("{} | {} | {} | {} msgs", s.id, s.name, s.backend, s.message_count);
            }
        }
        return;
    }

    // Handle --search
    if let Some(query) = matches.get_one::<String>("search_arg") {
        let sessions = session_manager.list();
        let query_lower = query.to_lowercase();
        for s in &sessions {
            if s.name.to_lowercase().contains(&query_lower) || s.id.contains(&query_lower) {
                println!("{} | {} | {}", s.id, s.name, s.backend);
            }
        }
        return;
    }



    let backend = create_backend(&config);
    // Create async backend for API-type backends
    let async_backend: Option<AsyncApiBackend> = {
        let b = config.backend.as_str();
        match b {
            "claude" | "openai" | "openrouter" | "ollama-api" => {
                // Reuse the same config to build async variant
                let key = config.api_key.clone();
                let model = config.model.clone().unwrap_or_default();
                let endpoint = match b {
                    "claude" => "https://api.anthropic.com/v1/messages",
                    "openai" => "https://api.openai.com/v1/chat/completions",
                    "openrouter" => "https://openrouter.ai/api/v1/chat/completions",
                    "ollama-api" => "http://localhost:11434/api/chat",
                    _ => "",
                };
                let api_format = if b == "claude" { "anthropic" } else { "openai" };
                Some(AsyncApiBackend::new(b, endpoint, key, &model, config.stream, api_format))
            }
            _ => None,
        }
    };
    let mut context = ContextManager::new(
        config.max_messages as usize,
        config.max_context_tokens,
        config.max_chars,
        config.max_words,
        &config.context_mode,
    );
    let mut cost_tracker = CostTracker::new();
    let mut tool_handler = ToolHandler::new(config.auto_tools, config.security_profile.clone(), config.approval_mode.clone());

    // Enable proot sandbox if requested via CLI or security profile
    if matches.get_flag("proot") {
        let proot_dirs: Vec<String> = matches.get_many::<String>("proot_allow_dir")
            .map(|vals| vals.map(|s| s.to_string()).collect())
            .unwrap_or_default();
        let cwd = std::env::current_dir().unwrap_or_default();
        tool_handler.enable_proot(&cwd.to_string_lossy(), proot_dirs);
    }

    // Load plugins from default directory
    let plugin_count = tool_handler.load_default_plugins();
    if plugin_count > 0 {
        println!("[Loaded {} plugin(s)]", plugin_count);
    }

    // Initialize MCP servers from config
    if !config.mcp_servers.is_empty() {
        use agent_loop::mcp_client::McpServerConfig;
        let mcp_configs: Vec<McpServerConfig> = config.mcp_servers.iter().filter_map(|s| {
            serde_json::from_value(s.clone()).ok()
        }).collect();
        if !mcp_configs.is_empty() {
            tool_handler.set_mcp_servers(&mcp_configs);
            if let Some(ref mgr) = tool_handler.mcp_manager {
                let tool_count = mgr.list_tools().len();
                if tool_count > 0 {
                    println!("[MCP: connected {} server(s), {} tool(s)]", mcp_configs.len(), tool_count);
                }
            }
        }
    }

    let mut state = RuntimeState {
        max_iterations: config.max_iterations,
        stream: config.stream,
        show_tokens: config.show_tokens,
        multiline: false,
        paste_mode: config.paste_mode.clone(),
    };

    // Session resume tracking
    let mut active_session_id: Option<String> = None;

    // Restore initial context from --session if any
    if let Some(session_id) = matches.get_one::<String>("session") {
        if let Some(session) = session_manager.load(session_id) {
            for msg in &session.messages {
                context.add_message(&msg.role, &msg.content);
            }
            active_session_id = Some(session.metadata.id.clone());
            println!("Loaded session: {} ({} messages)", session.metadata.name, session.metadata.message_count);
        } else {
            eprintln!("Session not found: {}", session_id);
        }
    }

    // Build system prompt from agent_md + skills + base prompt
    let agent_md_content = config.agent_md.as_deref().and_then(load_agent_md);
    let skill_contents = load_skills(&config.skills);
    let final_system_prompt = build_system_prompt(
        agent_md_content.as_deref(),
        &skill_contents,
        config.system_prompt.as_deref(),
    );
    if !final_system_prompt.is_empty() {
        config.system_prompt = Some(final_system_prompt);
    }

    // Retry configuration
    let retry_config = RetryConfig::default();

    // Single-prompt non-interactive mode
    if let Some(prompt) = matches.get_one::<String>("prompt") {
        context.add_message("user", prompt);
        let ctx_snapshot: Vec<Message> = context.get_context().to_vec();
        let spinner = Spinner::start("Thinking...");
        let response = if let Some(ref ab) = async_backend {
            if state.stream {
                spinner.stop();
                let response = ab.send_streaming_async(prompt, &ctx_snapshot, |token| {
                    print!("{}", token);
                    use std::io::Write;
                    std::io::stdout().flush().ok();
                }).await;
                println!();
                response
            } else {
                let ab_ref = ab;
                let ctx_ref = &ctx_snapshot;
                let r = retry_async(&retry_config, || async {
                    ab_ref.send_async(prompt, ctx_ref).await
                }).await.unwrap_or_default();
                spinner.stop();
                r
            }
        } else {
            let r = retry_with_backoff(&retry_config, || {
                Ok::<_, String>(backend.send_message(prompt, &ctx_snapshot))
            }).unwrap_or_default();
            spinner.stop();
            r
        };
        if !state.stream && !response.content.is_empty() {
            println!("{}", response.content);
        }
        cost_tracker.record_usage(&response.model, response.input_tokens, response.output_tokens);
        if state.show_tokens {
            println!("  {}", cost_tracker.format_summary());
        }
        return;
    }

    let mut rl = rustyline::DefaultEditor::new().expect("Failed to initialize readline");

    // Handle --prompt-interactive: inject initial prompt
    let mut initial_prompt = matches.get_one::<String>("prompt_interactive").cloned();

    println!("UnifyWeaver Agent Loop ({})", backend.name());
    println!("Type /help for commands, /exit to quit.\n");

    loop {
        let readline = if let Some(p) = initial_prompt.take() {
            Ok(p)
        } else {
            rl.readline(">>> ")
        };
        match readline {
            Ok(line) => {
                let input = line.trim();
                if input.is_empty() { continue; }

                // Paste detection + multi-line input handling
                let input = if state.multiline {
                    let ml = MultilineHandler::new();
                    let full = ml.read_explicit(&mut rl);
                    format!("{}\n{}", input, full)
                } else if state.paste_mode != "off" {
                    // Try paste detection first (respects paste_mode setting)
                    match MultilineHandler::detect_paste(input) {
                        PasteResult::Pasted { content, line_count, char_count } => {
                            if line_count > 5 {
                                println!("  [pasted {} lines ({} chars)]", line_count, char_count);
                            }
                            content
                        }
                        PasteResult::SingleLine(line) => {
                            if MultilineHandler::needs_continuation(&line) {
                                MultilineHandler::read_until_complete(&line, &mut rl)
                            } else {
                                line
                            }
                        }
                    }
                } else {
                    // Paste detection disabled — just check multiline triggers
                    if MultilineHandler::needs_continuation(input) {
                        MultilineHandler::read_until_complete(input, &mut rl)
                    } else {
                        input.to_string()
                    }
                };
                let input = input.trim();
                if input.is_empty() { continue; }
                let _ = rl.add_history_entry(input);

                // Handle slash commands
                if input.starts_with('/' ) {
                    let handled = handle_command(input, &mut context, &cost_tracker, &session_manager, backend.name(), &mut state, &mut config);
                    if handled { continue; }
                }

                // Process message
                let trimmed = context.add_message("user", input);
                if trimmed > 0 {
                    eprintln!("  [context] Trimmed {} old message(s) to stay within limits", trimmed);
                }
                let mut iterations = 0;

                loop {
                    let ctx_snapshot: Vec<Message> = context.get_context().to_vec();
                    let spinner = Spinner::start("Thinking...");
                    let response = if let Some(ref ab) = async_backend {
                        if state.stream {
                            spinner.stop();
                            print!("\n");
                            let response = ab.send_streaming_async(input, &ctx_snapshot, |token| {
                                print!("{}", token);
                                use std::io::Write;
                                std::io::stdout().flush().ok();
                            }).await;
                            println!();
                            response
                        } else {
                            let ab_ref = ab;
                            let ctx_ref = &ctx_snapshot;
                            let r = retry_async(&retry_config, || async {
                                ab_ref.send_async(input, ctx_ref).await
                            }).await.unwrap_or_default();
                            spinner.stop();
                            r
                        }
                    } else {
                        let r = retry_with_backoff(&retry_config, || {
                            Ok::<_, String>(backend.send_message(input, &ctx_snapshot))
                        }).unwrap_or_default();
                        spinner.stop();
                        r
                    };

                    if !state.stream && !response.content.is_empty() {
                        println!("\n{}", response.content);
                    }
                    cost_tracker.record_usage(&response.model, response.input_tokens, response.output_tokens);

                    if response.tool_calls.is_empty() {
                        // Parse structured output (JSON blocks) from response
                        let parsed = OutputParser::parse_response(&response.content, None);
                        if !parsed.json_blocks.is_empty() {
                            eprintln!("  [parsed {} JSON block(s) from response]", parsed.json_blocks.len());
                        }
                        context.add_message("assistant", &response.content);
                        break;
                    }

                    // Handle tool calls (concurrent when multiple)
                    context.add_tool_call_message(&response.content, response.tool_calls.clone());
                    if response.tool_calls.len() == 1 {
                        let tc = &response.tool_calls[0];
                        println!("  [tool: {}]", tc.name);
                        if !tool_handler.confirm_tool_execution(tc) {
                            context.add_tool_result(&tc.id, "[Tool execution declined by user]");
                        } else {
                            let result = tool_handler.execute(tc);
                            println!("  {}", if result.success { "OK" } else { "FAIL" });
                            context.add_tool_result(&tc.id, &result.output);
                        }
                    } else {
                        // Execute multiple tool calls concurrently via spawn_blocking
                        let tool_calls_owned: Vec<ToolCall> = response.tool_calls.clone();
                        let handler_arc = std::sync::Arc::new(std::sync::Mutex::new(&mut tool_handler));
                        let mut results_ordered: Vec<(String, String, ToolResult)> = Vec::new();
                        // Run sequentially but in spawn_blocking to not block the tokio runtime
                        for tc in &tool_calls_owned {
                            println!("  [tool: {}]", tc.name);
                            let handler = handler_arc.lock().unwrap();
                            if !handler.confirm_tool_execution(tc) {
                                results_ordered.push((tc.id.clone(), tc.name.clone(), ToolResult {
                                    success: false,
                                    output: "[Tool execution declined by user]".to_string(),
                                    tool_name: tc.name.clone(),
                                }));
                                drop(handler);
                                continue;
                            }
                            drop(handler);
                            let result = handler_arc.lock().unwrap().execute(tc);
                            println!("  [{}] {}", tc.name, if result.success { "OK" } else { "FAIL" });
                            results_ordered.push((tc.id.clone(), tc.name.clone(), result));
                        }
                        for (id, _name, result) in results_ordered {
                            context.add_tool_result(&id, &result.output);
                        }
                        drop(handler_arc);
                    }

                    iterations += 1;
                    if state.max_iterations > 0 && iterations >= state.max_iterations as usize {
                        println!("  [iteration limit reached]");
                        break;
                    }
                }

                if state.show_tokens {
                    println!("  {} | context: ~{} tokens ({} msgs)",
                        cost_tracker.format_summary(),
                        context.estimate_tokens(),
                        context.len());
                }
            }
            Err(rustyline::error::ReadlineError::Interrupted) |
            Err(rustyline::error::ReadlineError::Eof) => {
                // Auto-save: update existing session or create new
                if context.len() > 0 {
                    if let Some(ref id) = active_session_id {
                        session_manager.update(id, context.get_messages(), backend.name());
                        println!("Session updated: {}", id);
                    } else {
                        let id = session_manager.save(context.get_messages(), backend.name(), None);
                        println!("Session saved: {}", id);
                    }
                }
                println!("Goodbye!");
                break;
            }
            Err(e) => {
                eprintln!("Error: {}", e);
                break;
            }
        }
    }

    // Disconnect MCP servers on exit
    if let Some(ref mut mgr) = tool_handler.mcp_manager {
        mgr.disconnect_all();
    }
}
